insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('sport-studies:2-5-5-education-against-peds:mcq:e93d256d', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'mcq', 'mcq', 1, '{"question": "What is the main aim of an anti-doping awareness campaign run by a club or governing body?", "options": ["To put athletes off using banned substances before they are ever tempted to try them", "To remove the requirement for any athlete to ever be tested at a competition of any kind", "To reward athletes with prize money for reporting other competitors who dope", "To replace the entire set of written rules a sport has about banned substances"]}'::jsonb, '{"answer": 0, "explain": "Campaigns are a form of prevention — posters, workshops and talks aim to discourage use before an athlete ever considers it, not to change testing rules or offer rewards."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:mcq:a897b32d', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'mcq', 'mcq', 1, '{"question": "How can a respected role model help educate athletes against doping?", "options": ["By refusing to discuss the topic of doping with any athlete they coach or compete alongside", "By showing, through their own visible behaviour, that competing clean is the normal way to behave", "By guaranteeing that the athletes who copy them will win every future competition they ever enter", "By replacing the need for any official governing-body anti-doping campaign whatsoever"]}'::jsonb, '{"answer": 1, "explain": "A role model''s visible behaviour makes clean sport feel like the expected norm, which is far more persuasive than staying silent or claiming to remove the need for campaigns."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:mcq:d138bd12', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'mcq', 'mcq', 1, '{"question": "Why do peers and team-mates have such a strong influence on whether an athlete considers doping?", "options": ["They are with the athlete for most of their day-to-day training, shaping normal, everyday choices", "They are the only people who are ever legally allowed to discuss banned substances", "They are automatically better informed about doping than any qualified coach or governing body could ever be", "They have no real influence at all once an athlete has joined a senior squad"]}'::jsonb, '{"answer": 0, "explain": "Constant daily contact means peers shape what feels ''normal'', which is why their attitude matters more than a one-off talk from someone the athlete rarely sees."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:mcq:3ceda7a2', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'mcq', 'mcq', 1, '{"question": "What role can a family play in educating a young athlete against future PED use?", "options": ["Shaping the athlete''s early attitudes to fairness, so winning at any cost feels less acceptable", "Legally banning the athlete from ever taking part in competitive sport again", "Testing the athlete for banned substances before every single training session without exception", "Replacing the athlete''s coach as the only source of anti-doping information"]}'::jsonb, '{"answer": 0, "explain": "Family shape attitudes to honesty and fair play from a young age, long before formal education begins — they are not testers, and they do not replace coaches."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:mcq:fd39e4e0', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'mcq', 'mcq', 1, '{"question": "Why do anti-doping education programmes teach athletes about the health risks of PEDs?", "options": ["So athletes understand the real personal cost, since many risks only appear years later", "So athletes can safely reduce a health risk by taking a slightly smaller, measured dose", "So that governing bodies never need to mention the topic of health again after year one", "So that only elite, full-time professional athletes are ever warned about any risk at all"]}'::jsonb, '{"answer": 0, "explain": "Naming the real, often long-delayed health risks in advance is the point — there is no ''safe smaller dose'', and every level of athlete needs the same warning, not just elite ones."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:mcq:220919b7', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'mcq', 'mcq', 1, '{"question": "An athlete is offered an unfamiliar supplement by a training partner. What has good anti-doping education taught them to do?", "options": ["Take it immediately, because a training partner would never suggest something risky", "Check it against the current banned list, or ask a doctor, before taking anything unfamiliar", "Assume it is safe as long as it was bought legally from an ordinary high-street shop", "Say nothing to anyone and decide entirely alone, since checking would waste valuable training time anyway"]}'::jsonb, '{"answer": 1, "explain": "Education teaches athletes to check anything unfamiliar against the banned list or ask a professional first — trusting a training partner or a shop label is exactly how accidental doping happens."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:tf:ebffded0', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'tf', 'tf', 1, '{"question": "Anti-doping education aims to stop athletes doping before it happens, not only to punish them afterwards."}'::jsonb, '{"answer": true, "explain": "That is the whole point of education — prevention. Punishing athletes who have already doped is a separate, reactive response."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:tf:8b7fa685', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'tf', 'tf', 1, '{"question": "Only elite, famous athletes can ever act as a role model who influences someone against doping."}'::jsonb, '{"answer": false, "explain": "A role model can be a senior team-mate, a local coach or a family member — anyone an athlete looks up to and copies, not only famous professionals."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:tf:7236a475', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'tf', 'tf', 1, '{"question": "Team-mates can influence each other''s day-to-day choices about whether to use banned substances."}'::jsonb, '{"answer": true, "explain": "Because athletes train alongside team-mates constantly, what team-mates treat as normal has a real, daily influence on individual choices."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:tf:89a64d44', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'tf', 'tf', 1, '{"question": "Once a supplement is legal to buy in an ordinary shop, it is automatically safe for an athlete to take."}'::jsonb, '{"answer": false, "explain": "Some legal supplements contain substances that are banned in sport but not clearly listed — athletes must check the banned list, not just the shop label."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:tf:f9c3422a', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'tf', 'tf', 1, '{"question": "Understanding WHY a substance is banned can help the rule make more sense to an athlete."}'::jsonb, '{"answer": true, "explain": "Knowing the reason (unfair advantage, health danger, or against the spirit of sport) turns a rule from something arbitrary into something an athlete understands and accepts."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:tf:5651ab13', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'tf', 'tf', 1, '{"question": "Family have no real influence on an athlete''s attitude to fair play because doping is entirely a personal decision."}'::jsonb, '{"answer": false, "explain": "Family shape attitudes to honesty and fairness from a young age, well before any formal anti-doping education — so their influence is real, not irrelevant."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:learn:275b9ce8', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'learn', 'mcq', 1, '{"readingTitle": "Educating athletes to prevent doping — the big idea", "reading": "<h4>Why education, not just punishment</h4>\n<ul>\n<li>Sport does not only rely on catching cheats after the fact — a large amount of anti-doping work happens <strong>before</strong> an athlete ever considers taking a banned substance.</li>\n<li><strong>Education</strong> means teaching athletes the facts, the risks and the values of sport so that they choose not to dope in the first place, instead of only being deterred by the threat of a later sanction.</li>\n<li>Prevention through education matters because a drugs test can only catch someone who has already taken a substance — by that point, damage to health and to the sport''s reputation may already be done.</li>\n</ul>\n<h4>Campaigns that discourage use</h4>\n<ul>\n<li>Governing bodies, clubs and schools run <strong>awareness campaigns</strong> — posters, workshops, talks and online resources — aimed at putting athletes off using performance-enhancing drugs before they are ever tempted.</li>\n<li>A good campaign does more than say \"don''t do it\": it explains the health risks, the unfairness to other competitors, and the personal cost of being caught, in a way that actually changes behaviour rather than being ignored.</li>\n<li>Campaigns often target younger or developing athletes, because the attitudes formed early in a career are the ones most likely to last.</li>\n</ul>", "question": "What is the main advantage of educating athletes BEFORE they dope, compared with only punishing them afterwards?", "options": ["It removes the need for any drug testing at competitions from that point onwards", "It can stop the health damage and the unfairness from ever happening in the first place", "It guarantees that every athlete who takes part will certainly win a medal at their next event", "It means governing bodies no longer need any written rules about banned substances"]}'::jsonb, '{"answer": 1, "explain": "Education tries to stop doping before it starts, so the health damage and unfairness never happen — testing alone can only react once the damage is already done."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:learn:81e23148', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'learn', 'mcq', 1, '{"readingTitle": "Who does the educating — role models, peers and family", "reading": "<h4>Role models</h4>\n<ul>\n<li>A <strong>role model</strong> is someone an athlete looks up to and copies — often a more experienced athlete, a coach, or a well-known performer in their sport.</li>\n<li>When a role model speaks openly about competing clean, and is clearly seen rejecting shortcuts, it makes \"clean sport\" feel like the normal way to behave, rather than a rule forced on athletes from outside.</li>\n<li>A role model who stays silent, or who is seen bending the rules, sends the opposite message — which is why governing bodies use respected role models deliberately in education programmes.</li>\n</ul>\n<h4>Peers and team-mates</h4>\n<ul>\n<li>Athletes spend most of their training time with people of a similar age and ability, so <strong>peers and team-mates</strong> shape day-to-day decisions more than any single poster or leaflet ever could.</li>\n<li>A team-mate who questions a risky choice, or reports a concern, can stop doping before it starts; a team-mate who treats it as normal makes doping feel more acceptable.</li>\n</ul>\n<h4>Family</h4>\n<ul>\n<li><strong>Family</strong> shape an athlete''s attitude to fairness and honesty from a young age, long before any formal anti-doping education ever begins.</li>\n<li>A family that values effort and fair competition over winning at any cost reduces the pressure a young athlete feels to look for a shortcut later on.</li>\n</ul>", "question": "Why are peers and team-mates an important part of educating athletes against PED use?", "options": ["They are legally responsible for drug-testing every single athlete in their squad each week", "They train alongside the athlete most days, so their everyday attitudes shape real choices", "They make posters and leaflets unnecessary for any governing body ever again", "They only matter once an athlete has already reached full international level"]}'::jsonb, '{"answer": 1, "explain": "Team-mates are around an athlete constantly, so what they treat as normal or unacceptable has a daily influence that a poster or a one-off talk cannot match."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:learn:8334e644', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'learn', 'mcq', 1, '{"readingTitle": "What athletes must know — risks and clean sport", "reading": "<h4>The serious health risks</h4>\n<ul>\n<li>Education programmes teach athletes that performance-enhancing drugs are not a free shortcut — they carry <strong>serious health risks</strong>, including long-term damage to the body, disrupted hormones, and psychological effects such as dependency.</li>\n<li>Many of these risks only appear years later, which is exactly why athletes need to be warned about them in advance rather than finding out from experience.</li>\n</ul>\n<h4>The value of clean sport</h4>\n<ul>\n<li>Education also teaches the <strong>value of clean sport</strong> — the idea that a result only means something if every competitor had a genuinely fair chance of achieving it.</li>\n<li>Athletes are encouraged to see fair competition as something worth protecting for its own sake, rather than just a rule imposed on them by someone else.</li>\n</ul>\n<h4>Knowing exactly what is banned — and why</h4>\n<ul>\n<li>A large part of education is making sure athletes know <strong>precisely which substances and methods are banned</strong>, so that they never dope by accident — for example through an unchecked supplement or an everyday medicine.</li>\n<li>Athletes are taught to check any product against the current banned list, and to ask a doctor or official before taking anything unfamiliar, instead of assuming it must be fine.</li>\n<li>Understanding <em>why</em> something is banned (an unfair advantage, a health danger, or going against the spirit of sport) helps the rule make sense, rather than just feeling arbitrary.</li>\n</ul>", "question": "Why does education include teaching athletes exactly what is banned, rather than only that ''doping is against the rules''?", "options": ["So that they never accidentally take a banned substance in something like an unchecked supplement", "So that every athlete memorises the entire full banned list word for word before any single competition", "So that governing bodies can stop testing athletes at competitions altogether", "So that athletes never need to ask a doctor about any medicine again in future"]}'::jsonb, '{"answer": 0, "explain": "Knowing precisely what is banned, and why, protects athletes from doping by accident — the goal is informed choices, not word-for-word memorising or removing testing."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:misc:a419e7c1', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Education against PEDs is basically the same thing as punishing athletes who get caught doping.</p><p><strong>✅ The correct idea:</strong> Education and punishment are two separate tools. Education is PROACTIVE — it teaches facts, risks and values BEFORE any decision is made, aiming to stop doping happening at all. Punishment (sanctions) is REACTIVE — it responds after someone has already doped. An exam answer that only describes a sanction has not described an educational strategy.</p>", "question": "What is the key difference between EDUCATION and PUNISHMENT in anti-doping work?", "options": ["There is no real difference between the two at all", "Education happens before a decision is made; punishment happens after doping has occurred", "Punishment is always run by family members rather than governing bodies", "Education can only ever be delivered to athletes who have already been caught doping in competition"]}'::jsonb, '{"answer": 1, "explain": "Education tries to prevent doping before it happens; punishment reacts once it already has. Mixing the two up loses marks in an exam that asks specifically about education."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:misc:d5c117c4', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Only elite, famous athletes can act as a role model who influences someone against doping.</p><p><strong>✅ The correct idea:</strong> A role model is simply someone an athlete looks up to and copies — this can be a senior team-mate, a local coach, or a family member, just as much as a famous professional. Peers and family often have MORE day-to-day influence than a distant elite athlete an individual rarely meets in person.</p>", "question": "Which of these could act as a genuine role model in anti-doping education?", "options": ["A famous international athlete the person has never actually met", "A respected senior team-mate the athlete trains with every week", "Both a well-known professional AND a respected senior team-mate", "Neither of these, because only official campaigns can educate athletes"]}'::jsonb, '{"answer": 2, "explain": "Role models exist at every level — a famous athlete AND a respected team-mate can both shape attitudes, so limiting it to elite athletes alone misses the closer, daily influence."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:misc:3857f507', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If a product is a legal supplement bought on the high street, it must be safe for an athlete to use in competition.</p><p><strong>✅ The correct idea:</strong> Some legal, over-the-counter supplements can contain substances that are banned in sport without this being made obvious on the packaging. Education teaches athletes to check any unfamiliar product against the current banned list, or ask a doctor or official first, rather than trusting that ''legal to buy'' means ''safe to compete with''.</p>", "question": "Why can a legal, high-street supplement still be risky for a competing athlete?", "options": ["Because all supplements are illegal to sell in ordinary shops", "Because it might contain a banned substance not made clear on the packaging", "Because supplements are always more expensive than banned substances", "Because shops are legally required to report every single customer who buys one"]}'::jsonb, '{"answer": 1, "explain": "''Legal to buy'' is not the same as ''safe to compete with'' — some supplements contain undisclosed banned substances, which is exactly why checking the list matters."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:tips:4d05dd19', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Questions on educating athletes against PEDs are usually short recall or applied, but Section C can extend into a levelled discussion. Match your answer to the command word and the mark tariff:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two groups who can educate an athlete\" = two names, nothing more. 1 mark each.</li>\n<li><strong>Describe</strong> — give the features of a strategy, e.g. what an awareness campaign actually involves.</li>\n<li><strong>Explain</strong> — name a strategy AND give a reason it reduces doping. Use the word <em>because</em>.</li>\n<li><strong>Discuss</strong> — weigh up more than one side (for example education vs punishment) before reaching a judgement.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1]–[2] wants one or two clear points; higher marks in Section B want those points applied to the scenario in front of you.</p>", "question": "A question says: ''Identify two people or groups who can educate an athlete against doping [2]''. What is the safest answer?", "options": ["A detailed paragraph explaining only one group in full depth", "Two clearly named people or groups, such as a role model and family", "A list of every group you can possibly think of, however many that is", "A description of your own personal opinion about doping in sport"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' plus [2] wants two clear names — role models, peers/team-mates or family, for example — not one long explanation, an endless list, or a personal opinion."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:tips:22e93806', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the strategy AND explain why it works", "reading": "<p>The most common way to lose marks here is naming a strategy without saying why it reduces doping. Build every answer as <strong>strategy → who it reaches → why it helps</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Campaigns.\"</li>\n<li><strong>✅ full marks:</strong> \"Awareness campaigns explain the health risks of PEDs, which puts athletes off before they are ever tempted to try them.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario — a named club or athlete. You must link your strategy to a detail <em>from that scenario</em>, not a general example that ignores it.</p>", "question": "In a Section B scenario about a named athlete offered an unfamiliar supplement, your answer should link your strategy to...", "options": ["any general example you already happen to know well", "the specific detail given in the scenario", "a famous international athlete not mentioned anywhere in the question", "the exam board''s own official published guidance documents"]}'::jsonb, '{"answer": 1, "explain": "Section B rewards applying your knowledge to the scenario given — a general point that ignores the supplement detail in front of you is capped."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:tips:ad84005c', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> quick recall of who educates athletes (role models, peers, family, campaigns) in <strong>Section A</strong>; applied scenarios about a club or athlete in <strong>Section B</strong>; and it can feed a <strong>Section C</strong> discussion comparing education against punishment as ways to reduce doping.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Keep education and punishment separate in your head — one prevents, the other reacts.</li>\n<li>For every strategy, memorise one reason it works — that reason is usually where the mark sits.</li>\n<li>Remember athletes can dope <em>by accident</em> — education about checking the banned list is a strategy in its own right.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way athletes are educated against doping is… because…\"</li>\n<li>\"This matters because it reaches athletes before…\"</li>\n<li>\"On the other hand, education alone may not…\"</li>\n</ul>", "question": "Why is it useful to remember that education can prevent ACCIDENTAL doping, not just deliberate doping?", "options": ["It shows a strategy (checking the banned list) that punishment cannot replace", "It proves that deliberate doping no longer happens in any sport", "It means checking a banned list is now completely unnecessary", "It replaces every single other educational strategy covered anywhere on this entire topic"]}'::jsonb, '{"answer": 0, "explain": "Accidental doping is a real risk education specifically targets (via checking the banned list) — a point punishment cannot address, since it only reacts once doping has occurred."}'::jsonb),
('sport-studies:2-5-5-education-against-peds:fib:21fc08b7', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'fib', 'fib', 1, '{"question": "Anti-doping _____ use posters, workshops and talks to put athletes off using banned substances before they are ever tempted.", "blankOptions": {"B1": ["campaigns", "peers", "accident", "model"]}}'::jsonb, '{"blanks": {"B1": "campaigns"}}'::jsonb),
