('sport-studies:2-5-5-education-against-peds:fib:f4aa3452', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'fib', 'fib', 1, '{"question": "Athletes are taught to check any supplement against the banned list so they do not dope by _____.", "blankOptions": {"B1": ["chance", "campaigns", "peers", "accident"]}}'::jsonb, '{"blanks": {"B1": "accident"}}'::jsonb),
