('sport-studies:2-5-5-education-against-peds:match:df39cb07', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Anti-doping campaign”?", "options": ["The attitudes to fairness and honesty a young athlete picks up at home from an early age", "Confirming a supplement or medicine is allowed before taking it, to avoid doping by accident", "The idea that a result only means something if every competitor had a genuinely fair chance", "Posters, workshops and talks aimed at putting athletes off using banned substances before they are tempted"]}'::jsonb, '{"answer": 3, "explain": "“Anti-doping campaign” means: Posters, workshops and talks aimed at putting athletes off using banned substances before they are tempted"}'::jsonb),
('sport-studies:2-5-5-education-against-peds:match:0ce150c6', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Role model”?", "options": ["The attitudes to fairness and honesty a young athlete picks up at home from an early age", "The idea that a result only means something if every competitor had a genuinely fair chance", "A respected figure whose own visible behaviour shows athletes what counts as normal", "Posters, workshops and talks aimed at putting athletes off using banned substances before they are tempted"]}'::jsonb, '{"answer": 2, "explain": "“Role model” means: A respected figure whose own visible behaviour shows athletes what counts as normal"}'::jsonb),
('sport-studies:2-5-5-education-against-peds:match:3a6d84d4', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Peer influence”?", "options": ["Confirming a supplement or medicine is allowed before taking it, to avoid doping by accident", "A respected figure whose own visible behaviour shows athletes what counts as normal", "The everyday effect team-mates have on each other''s choices during training", "The attitudes to fairness and honesty a young athlete picks up at home from an early age"]}'::jsonb, '{"answer": 2, "explain": "“Peer influence” means: The everyday effect team-mates have on each other''s choices during training"}'::jsonb),
('sport-studies:2-5-5-education-against-peds:match:07cfa8ce', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Family education”?", "options": ["Confirming a supplement or medicine is allowed before taking it, to avoid doping by accident", "A respected figure whose own visible behaviour shows athletes what counts as normal", "The idea that a result only means something if every competitor had a genuinely fair chance", "The attitudes to fairness and honesty a young athlete picks up at home from an early age"]}'::jsonb, '{"answer": 3, "explain": "“Family education” means: The attitudes to fairness and honesty a young athlete picks up at home from an early age"}'::jsonb),
('sport-studies:2-5-5-education-against-peds:match:7af1555f', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Clean sport”?", "options": ["A respected figure whose own visible behaviour shows athletes what counts as normal", "The idea that a result only means something if every competitor had a genuinely fair chance", "The attitudes to fairness and honesty a young athlete picks up at home from an early age", "Posters, workshops and talks aimed at putting athletes off using banned substances before they are tempted"]}'::jsonb, '{"answer": 1, "explain": "“Clean sport” means: The idea that a result only means something if every competitor had a genuinely fair chance"}'::jsonb),
('sport-studies:2-5-5-education-against-peds:match:ae78cb5e', 'sport-studies', 'sport-studies:2-5-5-education-against-peds', '2.5.5 Education Against PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Checking the banned list”?", "options": ["The idea that a result only means something if every competitor had a genuinely fair chance", "The attitudes to fairness and honesty a young athlete picks up at home from an early age", "Posters, workshops and talks aimed at putting athletes off using banned substances before they are tempted", "Confirming a supplement or medicine is allowed before taking it, to avoid doping by accident"]}'::jsonb, '{"answer": 3, "explain": "“Checking the banned list” means: Confirming a supplement or medicine is allowed before taking it, to avoid doping by accident"}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:exam:4e7df287', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these is most likely to happen to sponsors after a sport suffers a major, repeated doping scandal?", "options": ["Sponsors increase their spending immediately, because doping scandals always attract far more media attention", "Sponsors may withdraw funding, because they do not want their brand linked to a ''tainted'' sport", "Sponsors are legally required to keep funding the sport for a further ten years", "Sponsors have no interest in a sport''s reputation at all"], "hint": "Think about why a company pays to have its brand seen alongside a sport in the first place.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Sponsors may withdraw funding, because they do not want their brand linked to a ''tainted'' sport.</strong></p>\n<ul>\n<li>Sponsors protect their own brand''s reputation, so a repeated scandal is a real financial risk to them.</li>\n<li>There is no legal requirement to keep funding, and scandal does not reliably increase sponsor spending.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:mcq:5abbf9b5', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'mcq', 'mcq', 1, '{"question": "Which of these best describes how a doping scandal can affect a SPORT, rather than just the one performer caught?", "options": ["It guarantees that the sport receives a large increase in government funding during the following season", "It has no lasting impact on anything once the individual performer has served their ban", "It can damage the sport''s overall reputation, because people start to question other results too", "It automatically doubles ticket sales for every future event the sport holds afterwards"]}'::jsonb, '{"answer": 2, "explain": "A scandal can damage the whole sport''s reputation, because people start doubting other results too — it does not guarantee extra funding, higher ticket sales, or simply vanish once one ban is served."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:mcq:7464a32c', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'mcq', 'mcq', 1, '{"question": "What can happen to public interest in a sport after repeated doping scandals?", "options": ["Public interest always rises very sharply after each scandal, because controversy makes the sport feel more exciting to watch", "Public trust and interest can fall, because fans no longer feel confident that results are genuine", "Nothing changes at all, because fans never pay attention to how a result was actually achieved", "Every broadcaster is legally required to stop showing the sport completely and permanently"]}'::jsonb, '{"answer": 1, "explain": "Repeated scandals can make fans doubt whether results are genuine, so trust and interest can fall — scandal does not reliably boost interest, and coverage is not simply banned outright."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:mcq:c81523a1', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'mcq', 'mcq', 1, '{"question": "Why is a result achieved using PEDs described as ''unfair or dishonest''?", "options": ["Because the performer received a harsher training schedule than everyone else in the competition", "Because the performer gained an advantage that their rivals were not allowed to use", "Because judges are legally required to disqualify every competitor immediately after the event", "Because the whole event has to be replayed in full from the very beginning the following week"]}'::jsonb, '{"answer": 1, "explain": "The result is unfair because the doped performer had an advantage rivals were not allowed to use — a harsher schedule, blanket disqualification and full replays are not what makes it dishonest."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:mcq:4b5dedce', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'mcq', 'mcq', 1, '{"question": "A clean athlete finishes fourth behind a rival who is later proven to have doped. How does this show the impact of PEDs on a sport?", "options": ["It shows that clean athletes always end up receiving more prize money than any doped rival eventually does", "It shows that doping bans are automatically cancelled once a result has already been publicly announced", "It shows that governing bodies refuse to ever re-examine a result once the medals have been given out", "It shows that a clean athlete can lose medals, funding and recognition to a rival who cheated"]}'::jsonb, '{"answer": 3, "explain": "The clean athlete missed out on medals, funding and recognition that their genuine performance should have earned — that lost opportunity is the real impact, not a guaranteed pay-out or a frozen result."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:mcq:e64700e1', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'mcq', 'mcq', 1, '{"question": "Why might sponsors withdraw funding from a sport after a major doping scandal?", "options": ["Sponsors are legally forced by government regulators to withdraw all funding from that sport", "Sponsors always increase their funding straight away, because scandals attract more media coverage", "Sponsors do not want their brand linked to a sport that now looks ''tainted'' by cheating", "Sponsors are only ever interested in individual athletes and never fund a sport as a whole"]}'::jsonb, '{"answer": 2, "explain": "Sponsors protect their brand by avoiding a ''tainted'' sport — it is a reputational choice, not a legal requirement, and scandal does not reliably attract extra sponsorship money."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:mcq:5fde692a', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'mcq', 'mcq', 1, '{"question": "Which statement best explains why anti-doping testing is described as an ''ongoing cost'' for a sport?", "options": ["Testing only ever has to happen once, right at the very start of an athlete''s professional sporting career", "Testing and policing have to continue constantly, because new substances and methods keep appearing", "Testing is completely free for every governing body, so it has no real cost to the sport at all", "Testing is cancelled automatically for a sport as soon as one athlete is caught and banned"]}'::jsonb, '{"answer": 1, "explain": "New substances and methods keep appearing, so testing and policing must keep adapting — that is why the cost is ongoing, not a single free or one-off event."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:tf:404501fa', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'tf', 'tf', 1, '{"question": "A doping scandal involving one athlete can damage the reputation of the whole sport."}'::jsonb, '{"answer": true, "explain": "Once one performer is caught, fans and the media often start to question the whole sport, not just that individual — the reputation damage spreads beyond one person."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:tf:8064aea2', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'tf', 'tf', 1, '{"question": "Public trust in a sport always increases straight after a doping scandal."}'::jsonb, '{"answer": false, "explain": "The opposite is more likely — fans can start doubting whether results are genuine, so trust and interest tend to fall, not rise."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:tf:e5cd0530', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'tf', 'tf', 1, '{"question": "A result achieved using PEDs is still fair, as long as the performer also trained hard."}'::jsonb, '{"answer": false, "explain": "Training hard does not cancel out the unfair advantage a PED gives — the result is still dishonest because rivals were not allowed to use the same boost."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:tf:019cef7c', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'tf', 'tf', 1, '{"question": "Clean athletes can lose medals, funding or sponsorship to a rival who is later proven to have doped."}'::jsonb, '{"answer": true, "explain": "Every podium place a doped athlete takes is one a clean athlete did not get, which can cost them medals, funding and sponsorship they otherwise would have earned."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:tf:33e05cc7', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'tf', 'tf', 1, '{"question": "Sponsors always increase their spending on a sport straight after a doping scandal breaks."}'::jsonb, '{"answer": false, "explain": "Sponsors more often pull money OUT of a sport that looks ''tainted'', because they do not want their brand linked to cheating."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:tf:0943ebac', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'tf', 'tf', 1, '{"question": "Anti-doping testing is an ongoing cost, because new substances and methods keep appearing."}'::jsonb, '{"answer": true, "explain": "Cheats keep finding new ways to dope, so testers must keep adapting what they test for — that constant effort is a genuine ongoing cost, not a one-off payment."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:learn:c3c8ec22', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'learn', 'mcq', 1, '{"readingTitle": "Reputation and public trust — the sport takes the hit", "reading": "<h4>It isn''t only the athlete''s name that suffers</h4>\n<ul>\n<li>When one performer is caught using a <strong>performance-enhancing drug (PED)</strong>, the story rarely stays about that person for long. Journalists, fans and rival competitors start asking whether the <strong>whole sport</strong> has a doping problem.</li>\n<li>That shift matters because it damages the <strong>sport''s reputation</strong> — not only the reputation of the individual who was caught.</li>\n</ul>\n<h4>Public trust and interest can fall</h4>\n<ul>\n<li>Once people suspect that some winners might be cheating, they can start to doubt <strong>every</strong> result in that sport — including performances that were completely clean.</li>\n<li>That loss of trust can shrink the audience: fewer people watch, follow or care about a sport they no longer believe is being won fairly, so <strong>public trust and interest can fall</strong>.</li>\n<li>A sport with a long history of doping cases can carry that damaged reputation for years, even long after it tightens its rules.</li>\n</ul>", "question": "A PED scandal involving one athlete breaks in the news. Why can this damage the sport as a whole?", "options": ["Because fans and the media can start to doubt every result in that sport, not only the athlete who was caught", "Because journalists automatically assume every single competitor in that sport must also be using banned substances", "Because the scandal has no effect on anyone except the one athlete who was actually caught doping", "Because governing bodies must permanently close down the sport within a year of any doping case being proven"]}'::jsonb, '{"answer": 0, "explain": "Doping scandals spread doubt onto the whole sport — damaging its reputation and public trust — not only the individual who was caught. The other options either overstate the effect or wrongly claim there is no wider effect at all."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:learn:7319f1bc', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'learn', 'mcq', 1, '{"readingTitle": "Unfair results — and the clean athletes who lose out", "reading": "<h4>Records and results built on a lie</h4>\n<ul>\n<li>A performance boosted by PEDs is not a fair contest — the result is <strong>unfair or dishonest</strong>, because the performer gained an advantage that their rivals were not allowed to use.</li>\n<li>If a record is later shown to have been set by a doped athlete, the record itself becomes tainted, even if it takes years for testing to catch up with it.</li>\n</ul>\n<h4>Clean athletes are the ones who really lose out</h4>\n<ul>\n<li>Every place a doped athlete takes on a podium is a place a <strong>clean athlete</strong> did not get. That can mean lost medals, lost prize money, lost funding and lost sponsorship for someone who did nothing wrong.</li>\n<li>Some clean athletes only receive their medal, title or funding years later, once a doping case is finally proven — by which point the moment, and often the money, has already gone.</li>\n</ul>", "question": "Why are clean athletes described as the group who ''lose out'' when a rival uses PEDs?", "options": ["Because they are automatically banned from competing again once someone else is caught doping", "Because a doped rival can take the medals, funding and sponsorship that a clean performance would otherwise have earned", "Because clean athletes are always physically slower than any athlete who has ever used a PED", "Because the governing body always disqualifies the clean athlete instead of the one who actually doped, even years after the case is proven"]}'::jsonb, '{"answer": 1, "explain": "A doped rival can take the medal, funding or sponsorship a clean athlete''s genuine performance would have earned — that is the real cost to clean athletes, not a ban or a disqualification of the wrong person."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:learn:8ec2cda9', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'learn', 'mcq', 1, '{"readingTitle": "The ongoing cost to the sport — money and policing", "reading": "<h4>Sponsors do not want to be linked to a ''tainted'' sport</h4>\n<ul>\n<li>Sponsors pay to have their brand linked to something exciting and trustworthy. A sport with a doping scandal can become <strong>\"tainted\"</strong> in the public eye, so sponsors may pull their money out rather than risk being linked to cheating.</li>\n<li>That loss of sponsorship and broadcast income can hit the whole sport financially — from the top level down to grassroots clubs that relied on money trickling down from it.</li>\n</ul>\n<h4>Testing and policing never really stop</h4>\n<ul>\n<li>To protect its reputation, a sport has to keep testing and monitoring performers — that is an <strong>ongoing cost</strong>, in money and staff time, that never truly ends.</li>\n<li>People looking to cheat keep finding new substances and methods, so testers must keep updating what they test for. That constant effort is a direct cost of PED use existing in the sport at all.</li>\n</ul>", "question": "Why does PED use create an ''ongoing'' cost for a sport, rather than a one-off cost?", "options": ["Because testing and policing have to continue and adapt constantly, which keeps costing money and staff time", "Because testing only ever has to happen once, on the very first day an athlete joins a professional sporting team", "Because every sponsor is legally required to pay the exact same fine to the sport every single year", "Because testing equipment never needs to be replaced or updated once it has first been bought"]}'::jsonb, '{"answer": 0, "explain": "New substances and methods keep appearing, so testing and policing must keep adapting — that ongoing effort and expense is why the cost never truly stops, unlike a single one-off payment."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:misc:9d6e387d', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Doping only really affects the one athlete who gets caught — it''s their problem, not the sport''s.</p><p><strong>✅ The correct idea:</strong> The exam wants you to explain the impact on the SPORT, not only the individual. A scandal can damage the sport''s reputation, reduce public trust and interest, disadvantage clean athletes who lose medals or funding, push sponsors to leave a ''tainted'' sport, and add an ongoing cost of testing and policing. An answer that only mentions the athlete''s own ban misses almost every mark available.</p>", "question": "A question asks you to explain the impact of PED use ON A SPORT. What should your answer focus on?", "options": ["Only the length of the individual athlete''s ban", "Effects on the sport itself — reputation, trust, clean athletes, sponsors and testing costs", "Only what happens to the athlete''s own personal fitness and training programme in the years afterwards", "Only the name of the substance the athlete used"]}'::jsonb, '{"answer": 1, "explain": "''Impact on the sport'' means reputation, public trust, fairness to clean athletes, sponsor money and the cost of policing — not just the individual''s own ban or fitness."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:misc:7b5dfb87', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If a doped result stood for years before anyone was caught, it doesn''t really matter any more.</p><p><strong>✅ The correct idea:</strong> It still matters. The result was unfair or dishonest at the time it was won, and any clean athlete who missed out on a medal, funding or recognition lost that opportunity permanently — a late correction does not give them back the years they lost. It also shows why ongoing testing matters: cases can take years to prove, during which the sport''s reputation keeps being damaged.</p>", "question": "A doping case is only proven years after the event. Why does this still matter to a clean athlete who finished just behind?", "options": ["It doesn''t matter, because the result cannot ever be looked at again by anyone", "They permanently lost medals, funding or recognition during the years before the case was proven", "It only matters to the governing body, never to the athlete", "The clean athlete automatically becomes ineligible to compete in any future event once the case is proven"]}'::jsonb, '{"answer": 1, "explain": "The clean athlete missed out on real opportunities — medals, funding, recognition — during the years before the case was proven, and that loss cannot simply be reversed later."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:misc:b3a14a17', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Testing and policing are a one-off cost a sport pays once, and then never worries about again.</p><p><strong>✅ The correct idea:</strong> Testing and policing are an ONGOING cost. New substances and methods keep appearing, so a sport must keep updating what it tests for and keep paying staff and laboratories to do it — the effort never really stops as long as the temptation to dope exists.</p>", "question": "Why can''t a sport just test athletes once and consider the job finished?", "options": ["Because testing laboratories always close down after their very first year of operation", "Because new substances and methods keep appearing, so testing must keep adapting", "Because athletes are only ever tested during their very first competition", "Because governing bodies are not allowed to test the same athlete twice"]}'::jsonb, '{"answer": 1, "explain": "New substances and methods keep appearing, which is exactly why testing and policing must be an ongoing effort rather than a single completed task."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:tips:a3d0a310', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Impact-of-PEDs questions vary a lot in length. Match your answer to the command word and the mark tariff:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name an impact. \"Identify one impact of PED use on a sport\" = one named effect, e.g. \"loss of public trust\". 1 mark.</li>\n<li><strong>Describe</strong> — say what the impact actually looks like, not just its name.</li>\n<li><strong>Explain</strong> — give a reason. Use the word <em>because</em>. \"Explain how PED use can affect sponsorship\" = the impact, plus why it happens.</li>\n<li><strong>Discuss</strong> — weigh up more than one impact and reach a judgement about which matters most, or how serious the overall damage is.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] in Section B wants two developed, applied points; [8] wants balanced analysis of several impacts plus a justified judgement.</p>", "question": "A question says: ''Identify one impact of PED use on a sport [1]''. What is the safest answer?", "options": ["A full paragraph explaining every possible impact", "One named impact, such as loss of public trust", "A list of every impact you can remember", "A description of the athlete''s own punishment"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [1] = one named impact. A full paragraph or a long list wastes time for a single mark, and the athlete''s own punishment is not an impact on the sport."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:tips:0e6c7cac', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: impact on the SPORT, not the individual", "reading": "<p>The single most common way to lose marks here is writing about the athlete''s own ban instead of the sport. Keep asking yourself: <strong>who does this sentence actually affect?</strong></p>\n<ul>\n<li><strong>❌ Off-target:</strong> \"The athlete is banned for four years and loses their funding.\"</li>\n<li><strong>✅ On-target:</strong> \"The sport''s reputation is damaged, because fans start to doubt whether other results in the same competition were also achieved fairly.\"</li>\n</ul>\n<p>In <strong>Section B</strong> you are given a scenario. Use a detail <em>from that scenario</em> (a named event, sponsor or governing body) rather than a generic example.</p>", "question": "In a Section B scenario about a doping case, your answer should focus mainly on...", "options": ["the athlete''s personal fitness routine", "the impact on the sport itself, using detail from the scenario", "an unrelated sport you happen to prefer", "the exact chemical name of the banned substance that was used in the case"]}'::jsonb, '{"answer": 1, "explain": "Section B rewards applying the impact-on-the-sport idea to the scenario you are given — personal fitness, an unrelated sport, or the chemical name earn nothing here."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:tips:16835321', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> quick recall in <strong>Section A</strong> (identify/describe an impact); applied points in <strong>Section B</strong> scenarios about a specific doping case; and it feeds <strong>Section C</strong> 8-mark Discuss/Evaluate answers about how serious the overall damage to a sport really is.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the six impacts in pairs: reputation + trust, fairness + clean athletes, sponsors + testing cost.</li>\n<li>Always link an impact to WHY it happens — \"sponsors leave BECAUSE the sport now looks tainted.\"</li>\n<li>For a Discuss/Evaluate answer, pick two or three impacts and finish with a judgement on which does the most lasting damage.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One impact on the sport is… because…\"</li>\n<li>\"This matters because it affects…\"</li>\n<li>\"However, a bigger long-term impact might be… because…\"</li>\n</ul>", "question": "Why is it useful to link each impact to a reason (''because…'') in a longer answer?", "options": ["It fills space without adding anything", "It shows understanding of WHY the impact happens, which is what earns marks", "It replaces the need to ever mention more than one impact anywhere in the whole answer", "It means you never need to reach a judgement"]}'::jsonb, '{"answer": 1, "explain": "Explaining WHY an impact happens shows real understanding, rather than just naming it — and a longer answer still needs a range of impacts plus a final judgement."}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:fib:56ffba9d', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'fib', 'fib', 1, '{"question": "A doping scandal can damage a sport''s _____, making fans doubt every result.", "blankOptions": {"B1": ["funding", "advantage", "interest", "reputation"]}}'::jsonb, '{"blanks": {"B1": "reputation"}}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:fib:3a091690', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'fib', 'fib', 1, '{"question": "Public trust and _____ in a sport can fall once fans suspect cheating is happening.", "blankOptions": {"B1": ["reputation", "interest", "tainted", "funding"]}}'::jsonb, '{"blanks": {"B1": "interest"}}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:fib:bc1ea226', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'fib', 'fib', 1, '{"question": "A result boosted by PEDs is unfair because the performer gained an _____ that rivals were not allowed to use.", "blankOptions": {"B1": ["reputation", "interest", "advantage", "funding"]}}'::jsonb, '{"blanks": {"B1": "advantage"}}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:fib:83b935ea', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'fib', 'fib', 1, '{"question": "Clean athletes can lose medals and _____ to a rival who is later proven to have doped.", "blankOptions": {"B1": ["tainted", "advantage", "interest", "funding"]}}'::jsonb, '{"blanks": {"B1": "funding"}}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:fib:71205c70', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'fib', 'fib', 1, '{"question": "Sponsors may pull their money out once a sport looks _____ by repeated doping cases.", "blankOptions": {"B1": ["reputation", "interest", "funding", "tainted"]}}'::jsonb, '{"blanks": {"B1": "tainted"}}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:match:ab457e64', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Reputation damage”?", "options": ["A sport''s fairness and trustworthiness is doubted by the public after a doping scandal", "Confidence that results are genuine, and the level of attention fans give the sport", "Money and staff time a sport must keep spending because doping methods keep changing", "An outcome shaped by a performance advantage rivals were not allowed to use"]}'::jsonb, '{"answer": 0, "explain": "“Reputation damage” means: A sport''s fairness and trustworthiness is doubted by the public after a doping scandal"}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:match:32fe071e', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Public trust and interest”?", "options": ["Confidence that results are genuine, and the level of attention fans give the sport", "An outcome shaped by a performance advantage rivals were not allowed to use", "How sponsors may see a sport once it becomes strongly linked with doping cases", "A sport''s fairness and trustworthiness is doubted by the public after a doping scandal"]}'::jsonb, '{"answer": 0, "explain": "“Public trust and interest” means: Confidence that results are genuine, and the level of attention fans give the sport"}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:match:96bd0a83', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Unfair / dishonest result”?", "options": ["How sponsors may see a sport once it becomes strongly linked with doping cases", "Losing medals, funding or sponsorship to a rival who is later proven to have doped", "An outcome shaped by a performance advantage rivals were not allowed to use", "A sport''s fairness and trustworthiness is doubted by the public after a doping scandal"]}'::jsonb, '{"answer": 2, "explain": "“Unfair / dishonest result” means: An outcome shaped by a performance advantage rivals were not allowed to use"}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:match:3bd4f5a1', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Clean athlete disadvantage”?", "options": ["Losing medals, funding or sponsorship to a rival who is later proven to have doped", "Confidence that results are genuine, and the level of attention fans give the sport", "An outcome shaped by a performance advantage rivals were not allowed to use", "Money and staff time a sport must keep spending because doping methods keep changing"]}'::jsonb, '{"answer": 0, "explain": "“Clean athlete disadvantage” means: Losing medals, funding or sponsorship to a rival who is later proven to have doped"}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:match:01c60ebf', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “''Tainted'' sport”?", "options": ["How sponsors may see a sport once it becomes strongly linked with doping cases", "A sport''s fairness and trustworthiness is doubted by the public after a doping scandal", "An outcome shaped by a performance advantage rivals were not allowed to use", "Losing medals, funding or sponsorship to a rival who is later proven to have doped"]}'::jsonb, '{"answer": 0, "explain": "“''Tainted'' sport” means: How sponsors may see a sport once it becomes strongly linked with doping cases"}'::jsonb),
('sport-studies:2-5-6-the-impact-of-peds-on-sport:match:d26b65af', 'sport-studies', 'sport-studies:2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Ongoing testing cost”?", "options": ["Money and staff time a sport must keep spending because doping methods keep changing", "Losing medals, funding or sponsorship to a rival who is later proven to have doped", "An outcome shaped by a performance advantage rivals were not allowed to use", "A sport''s fairness and trustworthiness is doubted by the public after a doping scandal"]}'::jsonb, '{"answer": 0, "explain": "“Ongoing testing cost” means: Money and staff time a sport must keep spending because doping methods keep changing"}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:exam:c4463a8d', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'exam', 'mcq', 1, '{"num": "2", "question": "Which type of major sporting event returns to the same host venue every time it is held?", "options": ["A regular event, since a completely new host city bids for it every single time", "A regular and recurring event, since the venue stays the same each time", "A ''one-off'' event, since the host only gets the chance a single time", "None of these types ever return to a venue more than once"], "hint": "Think about which type''s defining feature is a FIXED venue.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — A regular and recurring event.</strong></p>\n<ul>\n<li>It repeats on a schedule but stays at the same venue every time.</li>\n<li>A regular event moves host, and a ''one-off'' event is hosted only very rarely — neither returns to a fixed venue every time.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:mcq:99f74bdf', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'mcq', 'mcq', 1, '{"question": "A major sporting event repeats on a schedule, but a different city is chosen to host it every time. Which type of event is this?", "options": ["This is a regular and recurring event, because the exact same host venue is used every single time without exception", "This is a regular event, because it repeats on a schedule but the host changes each time", "This is a ''one-off'' event, because the host city gets only one single chance ever", "This is not a scheduled event at all, since no city can ever host it twice running"]}'::jsonb, '{"answer": 1, "explain": "Repeating on a schedule but moving host each time is the definition of a regular event — a regular and recurring event keeps the same venue, and a ''one-off'' barely repeats at all."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:mcq:d738c82a', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'mcq', 'mcq', 1, '{"question": "A country gets the chance to stage a summer multi-sport Games only once every few decades, if at all. Which type of major event is this?", "options": ["A regular event, because the host changes to a new city on a fixed yearly schedule", "A regular and recurring event, since the same city keeps hosting it every year", "A ''one-off'' event, since a host city gets this rare chance only very occasionally", "An event with no type at all, because it is simply too large to be classified"]}'::jsonb, '{"answer": 2, "explain": "Being hosted extremely rarely, as a once-in-a-generation opportunity, is exactly what makes an event ''one-off'' — the other options describe events that repeat far more often."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:mcq:bd8f65b6', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'mcq', 'mcq', 1, '{"question": "A national motor-racing event is staged at the same circuit every single season, year after year. Which type of event is this?", "options": ["A ''one-off'' event, since the host city only gets to stage that particular circuit race a single time in its history", "A regular event, because a different circuit bids to host the race each season", "A regular and recurring event, because it repeats and always returns to that same circuit", "An event with an entirely random schedule that changes without any real pattern"]}'::jsonb, '{"answer": 2, "explain": "Repeating on a schedule AND staying at the same venue every time is the definition of regular and recurring — a ''one-off'' would happen rarely, and a regular event would change host."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:mcq:e5f4d4bc', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'mcq', 'mcq', 1, '{"question": "Which of these is the best example of a regular event, rather than a regular and recurring one?", "options": ["An annual tennis championship that is always played at the same grounds every year", "A motor-racing event held at one fixed circuit for every single season of the calendar", "A club competition final that is played in a newly chosen host city every year", "A summer multi-sport Games that a country hosts only once in a generation"]}'::jsonb, '{"answer": 2, "explain": "A regular event repeats but changes host — a final moving to a new city each year fits that pattern, unlike the fixed-venue tennis or motor-racing examples, or the rare ''one-off'' Games."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:mcq:fadcdd8b', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'mcq', 'mcq', 1, '{"question": "Why does a host city for a ''one-off'' event usually invest so heavily in permanent, large-scale infrastructure?", "options": ["Because permanent infrastructure is always cheaper to build than temporary structures", "Because the national governing body legally requires permanent buildings for any event", "Because that host city may never get the chance to stage the event again", "Because temporary infrastructure is against the rules for every major sporting event"]}'::jsonb, '{"answer": 2, "explain": "Since a ''one-off'' host might never host the event again, it often builds for a lasting legacy — not because permanent building is cheaper or a strict rule of every event."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:mcq:b2fd33bb', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'mcq', 'mcq', 1, '{"question": "Why can a regular event''s rotating hosts share out the cost and workload of staging it over time?", "options": ["Because only one host city is ever legally permitted to bid for the event", "Because a new host bids to stage the event each time it is held", "Because regular events never actually require any facilities to be built", "Because the same single venue is reused for absolutely every edition"]}'::jsonb, '{"answer": 1, "explain": "A regular event moves between different bidding hosts, so the cost and effort of staging it is spread across several places over time — it is not stuck with one host or one venue."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:tf:343bce29', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'tf', 'tf', 1, '{"question": "A regular event is hosted in a different city each time it is held."}'::jsonb, '{"answer": true, "explain": "That''s the definition of a regular event — it repeats on a schedule, but a new host city is chosen every time."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:tf:1fc00546', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'tf', 'tf', 1, '{"question": "A ''one-off'' event is hosted in the same city every single year."}'::jsonb, '{"answer": false, "explain": "That describes a regular and recurring event. A ''one-off'' event is the opposite — it is hosted in a particular city only extremely rarely."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:tf:86f433e2', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'tf', 'tf', 1, '{"question": "A regular and recurring event returns to the same venue each time it is held."}'::jsonb, '{"answer": true, "explain": "Correct — it repeats on a schedule like a regular event, but unlike a regular event it keeps the same venue every time."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:tf:6b132b81', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'tf', 'tf', 1, '{"question": "All three types of major event happen only once and are never repeated."}'::jsonb, '{"answer": false, "explain": "Only a ''one-off'' event barely repeats. Both a regular event and a regular and recurring event repeat on a fixed schedule — they just differ in whether the host changes."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:tf:a3209a15', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'tf', 'tf', 1, '{"question": "Naming the correct type of event, with no example or reason, is usually enough to earn full exam marks."}'::jsonb, '{"answer": false, "explain": "Marks usually need a matching example or reason tied to the type, not just the type''s name on its own."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:tf:20652777', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'tf', 'tf', 1, '{"question": "A host city for a ''one-off'' event often builds permanent infrastructure because it may never get the chance to host again."}'::jsonb, '{"answer": true, "explain": "Correct — since the chance may never come round again, a ''one-off'' host tends to invest for a lasting legacy rather than a temporary setup."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:learn:291f76c9', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'learn', 'mcq', 1, '{"readingTitle": "What a ''major sporting event'' is, and why its type matters", "reading": "<h4>What counts as ''major''</h4>\n<ul>\n<li>A <strong>major sporting event</strong> is a large-scale competition that draws big numbers of participants, spectators, media coverage and often government or commercial money.</li>\n<li>The exam is far less interested in \"how big\" an event is and much more interested in <strong>how it is scheduled</strong> — where it is held, and whether it comes back to the same place.</li>\n</ul>\n<h4>Why the hosting pattern matters</h4>\n<ul>\n<li>A host city, governing body or sponsor plans very differently depending on whether an event visits <em>once only</em>, <em>every so often at a new venue</em>, or <em>every time at the same venue</em>.</li>\n<li>The key exam skill: correctly naming the type an event follows, and backing it up with a matching example — not just describing the sport itself.</li>\n</ul>", "question": "What does the specification mainly focus on when it sorts major sporting events into types?", "options": ["How much prize money the winning athlete or team receives", "The pattern of where, and how often, an event is hosted", "How many television channels choose to broadcast the event live", "Whether the event includes more than one sport in its programme"]}'::jsonb, '{"answer": 1, "explain": "The types are about the hosting pattern — whether the venue changes and how often the event repeats — not about prize money, broadcast reach or how many sports are involved."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:learn:eedaae02', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'learn', 'mcq', 1, '{"readingTitle": "Regular events — a different host each time", "reading": "<h4>The idea</h4>\n<ul>\n<li>A <strong>regular event</strong> repeats on a fixed schedule (for example, every year), but moves to a <strong>different host city or country</strong> each time it is held.</li>\n<li>Example: a major club competition''s final might be scheduled every year, yet a new city bids to stage it each time — one year in one country, the next year somewhere else entirely.</li>\n</ul>\n<h4>Why the moving host matters</h4>\n<ul>\n<li>Because the venue changes, each host usually has to build or adapt facilities almost from scratch, which can bring fresh investment and tourism to a new place every time.</li>\n<li>Fans and organisers cannot assume the same stadium or transport links will be used twice running, so planning restarts for every single edition.</li>\n</ul>", "question": "Which of these correctly describes a ''regular'' major sporting event?", "options": ["It is held only once, in a single host city, as a rare once-in-a-generation occasion for that host", "It is held every year at exactly the same fixed venue and never moves elsewhere", "It repeats on a schedule, but moves to a different host city each time it is held", "It has no fixed schedule and could be staged in any country at any random time"]}'::jsonb, '{"answer": 2, "explain": "''Regular'' means it repeats on a schedule AND changes host each time — unlike a once-only event, and unlike an event that stays at the same fixed venue every year."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:learn:d405b66d', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'learn', 'mcq', 1, '{"readingTitle": "''One-off'' events, and regular and recurring events", "reading": "<h4>''One-off'' events</h4>\n<ul>\n<li>A <strong>''one-off'' event</strong> is hosted in a particular city extremely rarely — often only once in a generation. It is a huge, once-in-a-lifetime undertaking for that host.</li>\n<li>Example: a summer multi-sport Games that a country might only get the chance to stage once every few decades, if it ever gets the chance at all.</li>\n</ul>\n<h4>Regular and recurring events</h4>\n<ul>\n<li>A <strong>regular and recurring event</strong> also repeats on a schedule (such as every year), but — unlike a regular event — it returns to the <strong>same venue</strong> every single time.</li>\n<li>Example: an annual tennis championship played at the same grounds every year, or a motor-racing event held at the same circuit every season.</li>\n</ul>\n<h4>The key difference to hold onto</h4>\n<ul>\n<li>All three types can repeat on a schedule — the real difference is entirely about whether, and how, the <strong>host location changes</strong>: a ''one-off'' event barely repeats at all; a regular event repeats but moves; a regular and recurring event repeats and stays exactly where it is.</li>\n</ul>", "question": "Which statement correctly describes a ''regular and recurring'' major sporting event?", "options": ["It is held on a repeating schedule and returns to the same venue every time it is staged", "It is held once only, in a single city, and is never staged again in future", "It repeats on a schedule but always moves to a completely new and different host city each time", "It has no fixed venue at all and no fixed schedule of any kind whatsoever"]}'::jsonb, '{"answer": 0, "explain": "Regular AND recurring means it repeats on a schedule (like a regular event) but keeps the SAME venue every time — the opposite of a regular event, which moves host each time."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:learn:61b6da0a', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'learn', 'mcq', 1, '{"readingTitle": "Telling the three types apart — the exam skill", "reading": "<h4>Name the type AND give a matching example</h4>\n<ul>\n<li>Writing \"it''s a one-off event\" on its own earns little. Marks usually come from pairing the <strong>correct type</strong> with a <strong>correct, matching example or reason</strong>.</li>\n<li>Weak answer: <em>\"The Games are a one-off event.\"</em> Strong answer: <em>\"The Games are a ''one-off'' event because a host city gets the chance to stage them only very rarely, so this may be its only opportunity.\"</em></li>\n</ul>\n<h4>Comparing the three types side by side</h4>\n<ul>\n<li><strong>Regular</strong> = repeats + host changes each time (e.g. a club competition final moving city to city).</li>\n<li><strong>''One-off''</strong> = barely repeats + a rare, huge undertaking (e.g. a summer multi-sport Games).</li>\n<li><strong>Regular and recurring</strong> = repeats + host stays the same (e.g. an annual championship at the same grounds).</li>\n</ul>\n<h4>Why the type matters to a host or organiser</h4>\n<ul>\n<li>A ''one-off'' host often builds large, permanent infrastructure from scratch, since it may never host the event again — a lasting legacy matters hugely to that decision.</li>\n<li>A regular event''s rotating hosts can bid competitively and share the workload and cost of the event around different places over time.</li>\n<li>A regular and recurring host can reuse and gradually improve the same venue every year, so it makes long-term investment in that one fixed site.</li>\n</ul>", "question": "A candidate answers a question about a named event by writing only ''It is a one-off event''. What is missing from this answer?", "options": ["Nothing at all — naming the type alone is already enough for full marks", "A correct example or reason that shows understanding of that type", "A description of the closing ceremony held at the event", "The exact date on which tickets first went on general sale"]}'::jsonb, '{"answer": 1, "explain": "Naming a type without a matching example or reason rarely earns full marks — the mark scheme rewards showing you understand WHY that type fits, not just stating a label."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:misc:a573e722', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> All three types of major event basically mean the same thing — they all just happen ''sometimes''.</p><p><strong>✅ The correct idea:</strong> They are three distinct patterns, and the exam rewards telling them apart. The difference is entirely about the HOST LOCATION: a regular event repeats but moves host; a ''one-off'' event barely repeats at all; a regular and recurring event repeats and stays at the same host. Saying an event ''happens sometimes'' shows none of that understanding.</p>", "question": "What is the real difference between the three types of major sporting event?", "options": ["There is no real difference between any of the three named types at all, ever", "Whether, and how, the host location changes between times the event is held", "How many spectators attend the event in a typical host city", "How much prize money is on offer to the eventual overall winner"]}'::jsonb, '{"answer": 1, "explain": "The types are defined entirely by the hosting pattern — does the venue change, stay the same, or barely repeat — not by attendance figures or prize money."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:misc:b5a56801', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''One-off'' must mean the event is small or unimportant, since it only happens once.</p><p><strong>✅ The correct idea:</strong> ''One-off'' describes the SCHEDULING PATTERN, not the size or importance of an event. In fact, ''one-off'' events (such as a summer multi-sport Games) are often among the very biggest events a host will ever stage — that is exactly why the chance to host one comes round so rarely.</p>", "question": "What does the term ''one-off'' actually describe about a major sporting event?", "options": ["That the event is small in scale and attracts little media attention", "That a host city gets the chance to stage it only very rarely", "That the event has already been permanently cancelled by organisers", "That the event is not a real sporting competition at all"]}'::jsonb, '{"answer": 1, "explain": "''One-off'' is about how rarely a host gets the chance — not about the event being small or unimportant. ''One-off'' events are often huge, once-in-a-generation occasions."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:misc:ae5887d6', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A regular event and a regular and recurring event are the same thing, since both repeat on a schedule.</p><p><strong>✅ The correct idea:</strong> Both do repeat on a schedule, which is exactly why students mix them up — but they differ in ONE key way: a regular event moves to a different host each time, while a regular and recurring event returns to the same host every time. That single difference is what the exam is testing.</p>", "question": "What is the one key difference between a regular event and a regular and recurring event?", "options": ["A regular and recurring event never actually follows any fixed schedule of any kind", "Whether the event returns to the same host venue, or moves to a new one each time", "A regular event is always far bigger in scale than a recurring one", "There genuinely is no difference between these two named types"]}'::jsonb, '{"answer": 1, "explain": "Both repeat on a schedule — the difference is purely whether the host location changes (regular) or stays the same (regular and recurring)."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:misc:bb3d1abd', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> In an exam answer, just writing the correct type''s name earns the same marks as explaining it.</p><p><strong>✅ The correct idea:</strong> Naming the type is usually only worth a mark on its own in the shortest ''Identify/State'' questions. For anything asking you to Describe or Explain, you must pair the type with a correct, matching example or reason — the name alone is not enough to reach full marks.</p>", "question": "For an ''Explain'' question about the type of a named event, what is most likely to earn the marks?", "options": ["Writing only the correct type name and nothing else at all", "Naming the type, then giving a matching example or reason", "Listing all three types you have learned", "Describing the sport being played at the event"]}'::jsonb, '{"answer": 1, "explain": "''Explain'' rewards a type PLUS a reason or example that fits it — naming the type alone, listing every type, or describing the sport itself does not show that understanding."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:tips:9b2265c9', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Questions on event types are usually short. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one type of major sporting event\" = one type name, nothing more. 1 mark.</li>\n<li><strong>Describe</strong> — say what the type is like. \"Describe a ''one-off'' event\" = give its features (rare, huge, once-in-a-generation).</li>\n<li><strong>Explain</strong> — give a reason, and usually an example. \"Explain why an event is regular and recurring\" = the pattern (same venue) plus why it fits.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2]–[4] want the type named AND applied to a given example or scenario.</p>", "question": "A question says: ''Identify one type of major sporting event [1]''. What is the safest answer?", "options": ["A full paragraph describing every type you know", "One correct type name", "The type''s name along with a full worked example", "A list of all three types with definitions"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [1] = one name, one mark. A full paragraph, or listing all three types, wastes time on a question only worth a single mark."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:tips:5ab2f6cb', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the type AND give a matching example", "reading": "<p>The single most common way to lose marks here is stopping at the type''s name. Build every answer as <strong>type → example/reason</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"It''s a one-off event.\"</li>\n<li><strong>✅ full marks:</strong> \"It''s a ''one-off'' event because the host city only gets the chance to stage it very rarely, so this may be its only opportunity.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named place or event). Use a detail <em>from that scenario</em> to justify the type — not just a general fact you already knew.</p>", "question": "In a Section B scenario question about a named event, your justification should come from...", "options": ["absolutely any event that you happen to know about", "the scenario you are given in the question", "an event that was hosted many decades ago", "your own personal opinion about which type sounds best"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you. A justification that ignores the scenario is capped."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:tips:eefda6c4', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this topic appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> event types appear as quick recall in <strong>Section A</strong> (identify/state), and as applied justification in <strong>Section B</strong> scenarios about a specific bid or host. They also feed <strong>Section C</strong> 8-mark answers weighing up hosting decisions for different event types.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the three types by their ONE defining feature each: moves (regular), rare (one-off), stays put (recurring).</li>\n<li>For every example you give, check it genuinely matches the type — don''t reuse the same example for two different types.</li>\n<li>In a longer answer, weigh up BOTH the benefits and the drawbacks of a type before reaching a judgement.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One benefit of this type of event is… because…\"</li>\n<li>\"However, a drawback of this type is… because…\"</li>\n<li>\"Overall, this type is the stronger choice because…\"</li>\n</ul>", "question": "Why is weighing up BOTH a benefit and a drawback useful in a longer answer on event types?", "options": ["It fills space without adding any real understanding", "It shows balanced analysis, which is what levelled questions reward", "It means you no longer need to reach any final, justified judgement at the end", "It replaces the need to give a correct example altogether"]}'::jsonb, '{"answer": 1, "explain": "Levelled (banded) questions reward balanced analysis of both sides before a judgement — a one-sided answer is capped in the middle band at best."}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:fib:165350fc', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'fib', 'fib', 1, '{"question": "A _____ event repeats on a schedule but is hosted in a different city each time it is held.", "blankOptions": {"B1": ["regular", "bid", "schedule", "recurring"]}}'::jsonb, '{"blanks": {"B1": "regular"}}'::jsonb),
