('sport-studies:3-1-1-types-of-major-events:fib:2e9945d6', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'fib', 'fib', 1, '{"question": "A ''one-off'' host often has to build permanent _____ from scratch, since it may never host again.", "blankOptions": {"B1": ["regular", "infrastructure", "bid", "schedule"]}}'::jsonb, '{"blanks": {"B1": "infrastructure"}}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:match:b4dcb46f', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Regular event”?", "options": ["Whether, and how often, a major event returns to the same host location", "A major event that repeats on a schedule but is hosted in a different city each time", "The pattern where a different city bids to stage an event each time it is held", "A major event hosted in a particular city extremely rarely, often only once in a generation"]}'::jsonb, '{"answer": 1, "explain": "“Regular event” means: A major event that repeats on a schedule but is hosted in a different city each time"}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:match:b238d17f', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “''One-off'' event”?", "options": ["A major event that repeats on a schedule but is hosted in a different city each time", "A major event hosted in a particular city extremely rarely, often only once in a generation", "A major event that repeats on a schedule and returns to the same venue every time", "The pattern where the same venue stages an event every time it is held"]}'::jsonb, '{"answer": 1, "explain": "“''One-off'' event” means: A major event hosted in a particular city extremely rarely, often only once in a generation"}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:match:1dae124a', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Regular and recurring event”?", "options": ["A major event hosted in a particular city extremely rarely, often only once in a generation", "A major event that repeats on a schedule but is hosted in a different city each time", "A major event that repeats on a schedule and returns to the same venue every time", "A description of how rarely a host city gets the chance to stage a ''one-off'' event"]}'::jsonb, '{"answer": 2, "explain": "“Regular and recurring event” means: A major event that repeats on a schedule and returns to the same venue every time"}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:match:914a83ea', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Rotating host”?", "options": ["The pattern where a different city bids to stage an event each time it is held", "A major event that repeats on a schedule but is hosted in a different city each time", "A description of how rarely a host city gets the chance to stage a ''one-off'' event", "The pattern where the same venue stages an event every time it is held"]}'::jsonb, '{"answer": 0, "explain": "“Rotating host” means: The pattern where a different city bids to stage an event each time it is held"}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:match:099418d6', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fixed host venue”?", "options": ["The pattern where the same venue stages an event every time it is held", "A major event that repeats on a schedule but is hosted in a different city each time", "A major event hosted in a particular city extremely rarely, often only once in a generation", "Whether, and how often, a major event returns to the same host location"]}'::jsonb, '{"answer": 0, "explain": "“Fixed host venue” means: The pattern where the same venue stages an event every time it is held"}'::jsonb)
